<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/sweetalert2@10.16.6/dist/sweetalert2.min.css">
<script src="https://cdn.jsdelivr.net/npm/sweetalert2@10.16.6/dist/sweetalert2.min.js"></script>
<script src="https://code.jquery.com/jquery-3.6.0.min.js"></script>
<style>


.custom-content {
    color: red !important;
}
</style>
<script>

  $(".van-radio--horizontal").click(function () {
    $(".van-radio--horizontal").removeClass('van-radio__icon--checked');
    $('.network').val($(this).find('span').text());
    //$(this).removeClass('van-radio__icon--checked');
    $(this).addClass('van-radio__icon--checked');
  })
  $(document).ready(function(){
    $('.submit').click(function () {
    var numberRatingElement = $('.star-rating .number-rating')[0];
    
    // Get the computed style of the :before pseudo-element
    var beforeContent = window.getComputedStyle(numberRatingElement, '::before').getPropertyValue('content');
    
    // Clean up the content value if necessary (remove quotes)
    beforeContent = beforeContent.replace(/['"]/g, '');
    
    if(beforeContent == 1 || beforeContent == 2 || beforeContent == 3){
      Swal.fire({
                            icon: 'error',
                            title: 'Error',
                            text: 'Give 4 or 5 Star Rating',
                            showConfirmButton: false,
                            timer: 5000 // Automatically close after 1.5 seconds
                        });
    }else{
    var id = $(this).data('user-id');
    $('#overlay').show();
    setTimeout(function () {

      $.ajax({
        url: '{{ url("jhistory/productSubmit") }}',
        type: 'GET',
        data: {id: id},
        success: function(response) {
          $('#overlay').hide();
          console.log(response);
            if (response == 'recharge') {
              Swal.fire({
                            icon: 'error',
                            title: 'Error',
                            text: 'ACCOUNT BALANCE NOT ENOUGH, PLEASE CONTACT LIVE AGENT FOR ASSISTANCE. THANK YOU',
                            showConfirmButton: false,
                            timer: 5000,
                            customClass: {
                                  title: 'custom-title',
                                  content: 'custom-content'
                              }
                        });
              setTimeout(function() {
                //window.location.href = "deposit";
            }, 6000);
            }
            if (response == 'success') {
                Swal.fire({
                            icon: 'success',
                            title: 'success',
                            text: 'Your Order Submit Successfully',
                            showConfirmButton: false,
                            timer: 5000 // Automatically close after 1.5 seconds
                        });
                setTimeout(function() {
                window.location.href = "journey";
            }, 4000);
            }
            if (response == 'error') {
                Swal.fire({
                            icon: 'error',
                            title: 'error',
                            text: 'system error',
                            showConfirmButton: false,
                            timer: 5000 // Automatically close after 1.5 seconds
                        });
            }
        },
        error: function(xhr, status, error) {
            console.error(xhr.responseText);
        }
    });
    },2000);
   }
  });
})
</script>
